import{_ as a,o as t,c as i,ag as l}from"./chunks/framework.BuUvxvtQ.js";const e="/assets/image-20250530003237275.D9DQr58o.png",k=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"Other/WSL.md","filePath":"Other/WSL.md","lastUpdated":1775898880000}'),n={name:"Other/WSL.md"};function d(p,s,h,o,r,c){return t(),i("div",null,[...s[0]||(s[0]=[l('<p>Windows专业版才支持Hyper-V服务，请确保系统是专业版。</p><p>打开以下服务：</p><ul><li>Hyper-V</li><li>Virtual Machine Platform</li><li>Windows虚拟机监控程序平台</li><li>适用于Linux的Windows子系统</li></ul><h3 id="wsl下载网络问题" tabindex="-1">wsl下载网络问题 <a class="header-anchor" href="#wsl下载网络问题" aria-label="Permalink to &quot;wsl下载网络问题&quot;">​</a></h3><p><img src="'+e+`" alt="image-20250530003237275"></p><p>如图不开代理无法与服务器建立连接，开了代理出现已禁止（403）</p><p>解决方案确保Windows相应服务被正常开启（家庭版的系统使用KMS升级为专业版），然后到Github上手动下载WSL的[release](<a href="https://github.com/microsoft/WSL/releases" target="_blank" rel="noreferrer">Releases · microsoft/WSL</a>)运行安装之后，在终端运行<code>wsl --install</code>默认下载<code>Ubuntu</code>。</p><h3 id="wsl移盘" tabindex="-1">wsl移盘 <a class="header-anchor" href="#wsl移盘" aria-label="Permalink to &quot;wsl移盘&quot;">​</a></h3><ul><li>导出它的备份（比如命名为 Ubuntu.tar）。在 CMD 命令行下输入“wsl --export Ubuntu- 24.04 E:\\Ubuntu\\Ubuntu_24_WSL\\Ubuntu.tar”。</li><li>确定在 E:\\Ubuntu\\Ubuntu_24_WSL 下是否可看见备份 Ubuntu.tar 文件， 之后注销原有的 WSL。 在 CMD 命令行输入<code>wsl --unregister Ubuntu-24.04</code>注销原本的 WSL。</li><li>将备份文件恢复到 E:\\Ubuntu\\Ubuntu_24_WSL 中去。在 CMD 命令行下输入“wsl -- import Ubuntu-24.04 E:\\Ubuntu\\Ubuntu_24_WSL E:\\Ubuntu\\Ubuntu_24_WSL\\Ubuntu.tar”恢复备份文件。</li></ul><h3 id="修改wsl默认启动挂载文件夹位置" tabindex="-1">修改WSL默认启动挂载文件夹位置 <a class="header-anchor" href="#修改wsl默认启动挂载文件夹位置" aria-label="Permalink to &quot;修改WSL默认启动挂载文件夹位置&quot;">​</a></h3><p>.bashrc 文件是 Bash 的配置文件之一，每次启动 Bash 时都会自动加载其中的配置。通过修改 .bashrc 文件，我们可以更加灵活地自定义 WSL 的启动行为，包括设置默认启动目录。</p><ol><li><p><strong>启动 WSL。</strong></p></li><li><p><strong>输入以下命令打开 .bashrc 文件：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>nano ~/.bashrc</span></span></code></pre></div><p>如果你更习惯使用 vi 或 vim 编辑器，也可以使用相应的命令打开 .bashrc 文件。</p></li><li><p><strong>将以下代码添加到 .bashrc 文件的末尾：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>if [ -d &quot;/mnt/d/your/desired/path&quot; ]; then</span></span>
<span class="line"><span>    cd /mnt/d/your/desired/path</span></span>
<span class="line"><span>fi</span></span></code></pre></div><p>请将 <code>/mnt/d/your/desired/path</code> 替换为你想要设置为默认启动目录的 Windows 文件夹路径。</p><p><strong>需要注意的是：</strong></p><ul><li>WSL 使用 <code>/mnt</code> 目录来挂载 Windows 磁盘分区，因此你需要根据实际情况修改路径。例如，若目标文件夹位于 D 盘，则路径应以 <code>/mnt/d</code> 开头。</li><li>代码中的 <code>if</code> 语句用于判断目标文件夹是否存在，以避免因路径错误导致启动失败。</li></ul><p>通过将这段代码添加到 .bashrc 文件中，就可以实现在每次启动 WSL 时，自动检查并进入指定的 Windows 文件夹。</p><p>此时启动ubuntu默认用户是root，修改为之前设定的用户</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ubuntu2004</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --default-user</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 刚刚建立的用户名</span></span></code></pre></div></li></ol><h3 id="解决wsl-检测到-localhost-代理配置-但未镜像到-wsl。nat-模式下的-wsl-不支持-localhost-代理。问题" tabindex="-1">解决<code>wsl: 检测到 localhost 代理配置，但未镜像到 WSL。NAT 模式下的 WSL 不支持 localhost 代理。</code>问题 <a class="header-anchor" href="#解决wsl-检测到-localhost-代理配置-但未镜像到-wsl。nat-模式下的-wsl-不支持-localhost-代理。问题" aria-label="Permalink to &quot;解决\`wsl: 检测到 localhost 代理配置，但未镜像到 WSL。NAT 模式下的 WSL 不支持 localhost 代理。\`问题&quot;">​</a></h3><p>在Windows的用户文件夹下创建<code>.wslconfig</code>文件写入以下内容</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[wsl2]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">autoMemoryReclaim</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">gradual</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">networkingMode</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">mirrored</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dnsTunneling</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">firewall</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">autoProxy</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">true</span></span></code></pre></div><p>执行<code>wsl --shutdown</code>之后再启动<code>wsl</code></p><h3 id="wsl打开子系统显示无图标" tabindex="-1">wsl打开子系统显示无图标 <a class="header-anchor" href="#wsl打开子系统显示无图标" aria-label="Permalink to &quot;wsl打开子系统显示无图标&quot;">​</a></h3><p><code>%USERPROFILE%\\AppData\\Local\\Packages\\Microsoft.WindowsTerminal_8wekyb3d8bbwe\\LocalState\\settings.json</code> 找到子系统设置那几行，我的是Ubuntu，添加icon配置</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;icon&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;图标的路径，注意使用双斜杠&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span></code></pre></div><h3 id="安装其它发行版" tabindex="-1">安装其它发行版 <a class="header-anchor" href="#安装其它发行版" aria-label="Permalink to &quot;安装其它发行版&quot;">​</a></h3><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">wsl </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">list </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">online </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#显示所有支持的发行版</span></span></code></pre></div><p>官方支持的发行版</p><table tabindex="0"><thead><tr><th>发行版名称</th><th>安装方式</th><th>备注</th></tr></thead><tbody><tr><td>Ubuntu（各版本）</td><td>wsl --install -d &lt;版本名称&gt;</td><td>包括 20.04、22.04、23.10 等</td></tr><tr><td>Debian</td><td>wsl --install -d Debian</td><td>稳定版</td></tr><tr><td>Kali Linux</td><td>wsl --install -d Kali-linux</td><td>渗透测试专用</td></tr><tr><td>Fedora Remix</td><td>wsl --install -d Fedora</td><td>社区维护版</td></tr><tr><td>OpenSUSE Leap</td><td>wsl --install -d openSUSE-Leap</td><td>SUSE 分支</td></tr><tr><td>AlmaLinux</td><td>wsl --install -d AlmaLinux</td><td>RHEL/CentOS 替代</td></tr><tr><td>Rocky Linux</td><td>wsl --install -d RockyLinux</td><td>RHEL/CentOS 替代</td></tr></tbody></table><p>设置wsl默认启动选项</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wslconfig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /setdefault</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 选项名</span></span></code></pre></div>`,25)])])}const g=a(n,[["render",d]]);export{k as __pageData,g as default};
